// --- Retry Helper ---
const retryWithBackoff = async <T>(fn: () => Promise<T>, retries = 3, delay = 2000): Promise<T> => {
    try {
        return await fn();
    } catch (err: any) {
        // Check for 429 (Resource Exhausted) or 503 (Service Unavailable)
        // The error object might be complex, so checking multiple properties
        const isRateLimit = 
            err?.status === 429 || 
            err?.code === 429 || 
            err?.statusText === 'RESOURCE_EXHAUSTED' ||
            (err?.message && (err.message.includes('429') || err.message.includes('quota')));

        if (retries > 0 && isRateLimit) {
            console.warn(`Quota exceeded. Retrying in ${delay}ms... (${retries} retries left)`);
            await new Promise(r => setTimeout(r, delay));
            return retryWithBackoff(fn, retries - 1, delay * 2);
        }
        throw err;
    }
}

