export const analyzeStock = async (query: string, mode: 'flash' | 'pro' = 'flash'): Promise<AIAnalysisResult> => {
  try {
    const dateObj = new Date();
    const year = dateObj.getFullYear();
    const month = String(dateObj.getMonth() + 1).padStart(2, '0');
    const day = String(dateObj.getDate()).padStart(2, '0');
    const hours = String(dateObj.getHours()).padStart(2, '0');
    const minutes = String(dateObj.getMinutes()).padStart(2, '0');
    const seconds = String(dateObj.getSeconds()).padStart(2, '0');

    const now = `${year}/${month}/${day} ${hours}:${minutes}:${seconds}`;
    const timeStr = `${hours}:${minutes}:${seconds}`;

    const prompt = `
      Current System Time (Taiwan): ${now}
      Target Stock: "${query}"

      **ROLE**: You are a VETERAN Taiwan Stock Market Analyst (20+ years experience). You do not trust simple technical indicators. You look for "TRAPS" set by institutional players.

      **CRITICAL SEARCH INSTRUCTIONS**:
      1. PRICE: Get real-time price using query "${query} 股價 live".
      2. **CHIP INSIDER (MOST IMPORTANT)**: Search for "${query} 隔日沖 券商", "${query} 主力籌碼", "${query} 凱基台北", "${query} 摩根大通". 
         - Detect if "Day Trading Whales" (隔日沖主力) bought heavily yesterday/today.
      3. **REGULATORY CHECK**: Search for "${query} 處置股", "${query} 注意股", "${query} 警示股". 
         - If listed as Disposition (處置) or Warning (注意), liquidity is restricted.
      4. **RETAIL SENTIMENT**: Search for "${query} 融資餘額", "${query} 借券賣出".
         - High Margin Debt (融資高) + Price Drop = FATAL SIGN.

      **SCORING & LOGIC (VETERAN MODE)**:

      **KILLER RULES (Instant Score Penalty)**:
      - **IF "Disposition Stock" (處置股)**: MAX overallScore = 60. Action = HOLD/SELL. Reason: No liquidity.
      - **IF "Day Trading Whales" (隔日沖) detected**: 
          - Example: Top buyers are "Morgan Stanley (Taiwan)", "Kaigi Taipei", "Merrill Lynch".
          - If they bought > 20% of volume yesterday, PROBABILITY of a dump today/tomorrow is 90%.
          - Action: CAUTION/SELL. Mark as "High Risk of Pullback".
      - **IF Price < MA20 AND Margin Debt (融資) is Increasing**: Action = SELL. Retail is trapped.

      **SCORING FORMULA (0-100)**:
      1. Fundamentals (25%): EPS, Growth.
      2. Technicals (15%): KD, MACD (Lower weight, can be fake).
      3. **Chips (Institutional/Whale) (30%)**: Foreign/Investment Trust = Good. Day Traders = BAD.
      4. Industry (15%): Sector trend.
      5. **Retail/Counter-Indicator (15%)**: Low Margin Debt is Good.

      **OUTPUT REQUIREMENTS**:
      - **warningFlags**: An array of strings. EXTREMELY IMPORTANT.
        - e.g., ["⚠️ 處置股票 (流動性風險)", "🐋 隔日沖進駐 (凱基台北)", "📉 融資過高 (散戶多殺多)", "💣 主力出貨嫌疑"]
      - **tradeSetup**: Provide a realistic "Probability" and "Risk/Reward Ratio" (e.g. "1:3").
      - **Language**: Traditional Chinese (繁體中文).
    `;

    const config: any = {
      tools: [{googleSearch: {}}],
      responseMimeType: "application/json",
      responseSchema: analysisSchema,
    };

    if (mode === 'pro') {
      config.thinkingConfig = { thinkingBudget: 16384 };
    }

    const response = await retryWithBackoff(() => 
      ai.models.generateContent({
        model: mode === 'pro' ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview',
        contents: prompt,
        config: config
      })
    );

    if (!response.text) throw new Error("No response");

    const data = JSON.parse(response.text) as AIAnalysisResult;
    data.timestamp = now;

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
        data.sources = chunks
            .map((c: any) => c.web)
            .filter((w: any) => w !== undefined)
            .map((w: any) => ({ title: w.title || 'Source', uri: w.uri || '#' }));
    }

    return data;
  } catch (error) {
    console.error("Analysis failed:", error);
    throw error;
  }
};

export const getDashboardData = async (): Promise<DashboardData> => {
    try {
        const cached = localStorage.getItem(CACHE_KEY);
        if (cached) {
            const { timestamp, data } = JSON.parse(cached);

            // Check if cache is still valid based on 12:00 PM cutoff
            const currentPeriod = getCachePeriodId(Date.now());
            const cachedPeriod = getCachePeriodId(timestamp);

            if (currentPeriod === cachedPeriod) {
                return data;
            }
        }
    } catch (e) {
        console.error("Cache read error", e);
    }

    const listsPrompt = `Fetch standard market ranking lists for TWSE. Traditional Chinese.`;
    const strategiesPrompt = `Identify 3 current hot market themes/concepts for TWSE. Traditional Chinese.`;

    try {
        const listsResponse = await retryWithBackoff(() => 
            ai.models.generateContent({
                model: "gemini-3-flash-preview",
                contents: listsPrompt,
                config: { tools: [{googleSearch: {}}], responseMimeType: "application/json", responseSchema: dashboardListsSchema }
            })
        );

        await new Promise(r => setTimeout(r, 1000));

        const strategiesResponse = await retryWithBackoff(() => 
            ai.models.generateContent({
                model: "gemini-3-flash-preview",
                contents: strategiesPrompt,
                config: { tools: [{googleSearch: {}}], responseMimeType: "application/json", responseSchema: strategiesSchema }
            })
        );

        const listsData = listsResponse.text ? JSON.parse(listsResponse.text) : {};
        const strategiesData = strategiesResponse.text ? JSON.parse(strategiesResponse.text) : {};

        const result: DashboardData = {
            trending: listsData.trending || [],
            fundamental: listsData.fundamental || [],
            technical: listsData.technical || [],
            chips: listsData.chips || [],
            dividend: listsData.dividend || [],
            strategies: strategiesData.strategies || []
        };

        localStorage.setItem(CACHE_KEY, JSON.stringify({ timestamp: Date.now(), data: result }));
        return result;
    } catch (e) {
        const cached = localStorage.getItem(CACHE_KEY);
        return cached ? JSON.parse(cached).data : { trending: [], fundamental: [], technical: [], chips: [], dividend: [], strategies: [] };
    }
}

